public function handle(Request $request, Closure $next, string $role): Response {
    if ($request->user() && $request->user()->role !== $role) {
        return redirect('/dashboard')->with('error', 'Akses ditolak!');
    }
    return $next($request);
}

public function handle(Request $request, Closure $next): Response {
    $request->headers->set('Accept', 'application/json');
    return $next($request);
}

public function terminate(Request $request, Response $response): void {
    if ($request->user()) {
        ActivityLog::create([
            'user_id' => $request->user()->id,
            'action' => $request->method() . ' ' . $request->fullUrl(),
            'payload' => $request->except(['password', 'token']),
        ]);
    }
}

public function handle(Request $request, Closure $next): Response {
    $allowedIps = ['127.0.0.1', '1.2.3.4'];
    if (app()->isDownForMaintenance() && !in_array($request->ip(), $allowedIps)) {
        abort(503);
    }
    return $next($request);
}

public function handle(Request $request, Closure $next): Response {
    $response = $next($request);
    $response->headers->set('X-Content-Type-Options', 'nosniff');
    $response->headers->set('X-Frame-Options', 'DENY');
    $response->headers->set('Content-Security-Policy', "default-src 'self'");
    return $response;
}

public function handle(Request $request, Closure $next): Response {
    $locale = $request->getPreferredLanguage(['id', 'en']);
    app()->setLocale($locale);
    return $next($request);
}
